async function initHomeArtistsPreview(){console.log("[homeArtistsPreview] init — readyState:",document.readyState);const t=document.getElementById("homeArtistsGrid");if(t){t.innerHTML='<p class="muted">Loading artists...</p>';try{const e=await fetchArtistsFromSanity(3);if(console.log("[homeArtistsPreview] data loaded —",(e||[]).length,"artists"),e&&e.length>0&&console.log("[homeArtistsPreview] sample artist:",JSON.stringify({_id:e[0]._id,name:e[0].name,slug:e[0].slug,hasImage:!!e[0].image?.asset?.url,style:e[0].style})),!e||!e.length)return void(t.innerHTML='<p class="muted">No artists available.</p>');console.log("[homeArtistsPreview] render artists"),t.innerHTML=e.map(t=>{const e=t.slug||t._id,s=t.image?.asset?.url||null,a=s?"function"==typeof window.sanityImgUrl?window.sanityImgUrl(s,{w:300,h:300,fit:"crop",q:80}):s:"images/artists/placeholder.jpg";return`\n        <a class="artist-card"\n           href="artists/artist.html?artist=${encodeURIComponent(e)}">\n\n          <div class="artist-avatar"\n               style="background-image:url('${a}')"></div>\n\n          <h3 class="artist-name">\n            <img src="images/icon.jpg" class="flag-icon" alt="">\n            <span>${t.name}</span>\n          </h3>\n\n          ${t.style?`<p class="artist-style">${t.style}</p>`:""}\n        </a>\n      `}).join("")}catch(e){console.error("❌ Failed to load artists on home page",e),t.innerHTML='<p class="muted">Failed to load artists.</p>'}}}"loading"===document.readyState?document.addEventListener("DOMContentLoaded",initHomeArtistsPreview):initHomeArtistsPreview();